int main_wrapper() {
    int matrix[3][3] = {
        {10, 20, 30},
        {40, 50, 60},
        {70, 80, 90}
    };
    int correct_sum = 0;
    for (int i = 0; i < 3; ++i) {
        for (int j = 0; j < 3; ++j) {
            correct_sum += matrix[i][j];
        }
    }
    std::cout << "Sum of all elements: " << correct_sum << std::endl;
    return 0;
}
